module RefModule(clk, rst, en, out);input clk, rst, en;
    output [3:0] out;

    reg [3:0] obf_count;

    always @(posedge clk or posedge rst)
    begin
        if (rst)
            obf_count <= 4'd0;
        else if (en)
            obf_count <= obf_count + 1;
    end

    assign out = obf_count;
endmodule
